import { useState, useEffect, useRef } from "react";
import "../styles/Stats.css";

export default function Stats() {
  const stats = [
    { label: "Projects Completed", value: 500 },
    { label: "Clients Served", value: 300 },
    { label: "Years of Experience", value: 2 },
    { label: "Team Members", value: 25 },
    { label: "Client Satisfaction", value: 100, suffix: "%" },
  ];

  const [currentIndex, setCurrentIndex] = useState(0);
  const [animatedValues, setAnimatedValues] = useState(stats.map(() => 0));
  const [inView, setInView] = useState(false);
  const statsSectionRef = useRef(null);

  useEffect(() => {
    const observer = new IntersectionObserver(
      (entries) => {
        entries.forEach((entry) => {
          if (entry.isIntersecting) {
            setInView(true);
          }
        });
      },
      { threshold: 0.5 }
    );

    const currentRef = statsSectionRef.current;
    if (currentRef) observer.observe(currentRef);

    return () => {
      if (currentRef) observer.unobserve(currentRef);
    };
  }, []);

  useEffect(() => {
    if (!inView || currentIndex >= stats.length) return;

    const currentStat = stats[currentIndex];
    if (currentStat.isText) {
      setAnimatedValues((prev) =>
        prev.map((val, i) => (i === currentIndex ? currentStat.value : val))
      );
      setTimeout(() => setCurrentIndex((prev) => prev + 1), 500);
      return;
    }

    const interval = setInterval(() => {
      setAnimatedValues((prevValues) => {
        const newValues = [...prevValues];
        const target = currentStat.value;
        const currentVal = newValues[currentIndex];

        if (currentVal < target) {
          newValues[currentIndex] = Math.min(currentVal + Math.ceil(target / 50), target);
        } else {
          clearInterval(interval);
          setCurrentIndex((prev) => prev + 1);
        }

        return newValues;
      });
    }, 30);

    return () => clearInterval(interval);
  }, [inView, currentIndex]);

  return (
    <section ref={statsSectionRef} className="stats-section">
      {stats.map((stat, index) => (
        <div key={index} className="stat-item">
          <h4>
            {stat.isText
              ? stat.value
              : `${animatedValues[index]}${stat.suffix || "+"}`}
          </h4>
          <p>{stat.label}</p>
        </div>
      ))}
    </section>
  );
}
